const notesMatieres = new Map();
notesMatieres.set('Maths', [12, 15, 18]);
notesMatieres.set('Francais', [14, 11, 16]);

function calculerMoyenne(matieresMap, matiere) {
  const notes = matieresMap.get(matiere);
  if (!notes) return null;
  const somme = notes.reduce((acc, note) => acc + note, 0);
  return somme / notes.length;
}

console.log(calculerMoyenne(notesMatieres, 'Maths')); // 15

