const getCompetencesPrincipales = Symbol('getCompetencesPrincipales');

const projet = {
  membres: new Set(),

  ajouterMembre(membre) {
    if (membre.id && membre.nom) {
      this.membres.add(membre);
      membre.competences = new Map();
    }
  },

  ajouterCompetence(membreId, competence, niveau) {
    const membre = [...this.membres].find(m => m.id === membreId);
    if (membre) {
      membre.competences.set(competence, niveau);
    }
  },

  [getCompetencesPrincipales](membreId) {
    const membre = [...this.membres].find(m => m.id === membreId);
    if (!membre) return [];
    const resultats = [];
    for (let [comp, niveau] of membre.competences) {
      if (niveau > 8) resultats.push({ comp, niveau });
    }
    return resultats;
  }
};

// Utilisation
const m1 = { id: 1, nom: 'Alice' };
projet.ajouterMembre(m1);
projet.ajouterCompetence(1, 'JavaScript', 9);
projet.ajouterCompetence(1, 'HTML', 7);
console.log(projet[getCompetencesPrincipales](1)); // [{ comp: 'JavaScript', niveau: 9 }]
